 * @Description:
 * @!: *********************************************************************
--&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E4%B8%8B%E8%BD%BD%E5%AE%89%E8%A3%85&#34;&gt;下载安装&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E6%8D%A2%E6%BA%90&#34;&gt;换源&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E9%85%8D%E7%BD%AE%E9%9D%99%E6%80%81-ip&#34;&gt;配置静态 IP&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E8%BD%AF%E4%BB%B6%E5%A4%87%E4%BB%BD&#34;&gt;软件备份&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;下载安装&#34;&gt;下载安装&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;官网上下载 ISO 文件就行,挺快的&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;desktop 是桌面版,有图形界面&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;server 是服务器版,没有图形界面(也就是只有命令行界面)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;我用的&lt;code&gt;VMware&lt;/code&gt;安装的,用其他软件也可,个人比较喜欢这个.&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;安装时可以选择附带的服务软件,比如&lt;code&gt;docker&lt;/code&gt;,&lt;code&gt;k8s&lt;/code&gt;等等…&lt;/li&gt;
&lt;/ul&gt;
&lt;hr&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;安装完成后长这样&lt;/p&gt;
&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/blog/GV4SqX.png&#34; alt=&#34;20210202144325&#34; /&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;换源&#34;&gt;换源&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;a href=&#34;https://blog.csdn.net/xiangxianghehe/article/details/105688062&#34;&gt;Ubuntu 20.04 换国内源 清华源 阿里源 中科大源 163 源&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ul&gt;
&lt;li&gt;安装系统过程中就有换源选项.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;配置静态-IP&#34;&gt;配置静态 IP&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;a href=&#34;https://www.cnblogs.com/yaohong/p/11593989.html&#34;&gt;ubuntu 18.04 设置静态 ip 方法&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;初始的 Ubuntu-Server 没有&lt;code&gt;net-tools&lt;/code&gt;,需要&lt;a href=&#34;#%E8%BD%AF%E4%BB%B6%E5%A4%87%E4%BB%BD&#34;&gt;安装&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;默认情况下使用&lt;code&gt;DHCP&lt;/code&gt;,连接网络会自动分配一个 IP,使用&lt;code&gt;ifconfig&lt;/code&gt;查看(这个 ifconfig 就是上面 net-tools 里面的)&lt;/p&gt;
&lt;figure class=&#34;highlight apache&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attribute&#34;&gt;weidows&lt;/span&gt;@ubuntu-server:~/Code$ ifconfig&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attribute&#34;&gt;ens33&lt;/span&gt;: flags=&lt;span class=&#34;number&#34;&gt;4163&lt;/span&gt;&amp;lt;UP,BROADCAST,RUNNING,MULTICAST&amp;gt;  mtu &lt;span class=&#34;number&#34;&gt;1500&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;inet&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;192.168.2.122&lt;/span&gt;  netmask &lt;span class=&#34;number&#34;&gt;255.255.255.0&lt;/span&gt;  broadcast &lt;span class=&#34;number&#34;&gt;192.168.2.255&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;inet6&lt;/span&gt; fe80::&lt;span class=&#34;number&#34;&gt;20&lt;/span&gt;c:&lt;span class=&#34;number&#34;&gt;29&lt;/span&gt;ff:fe28:c082  prefixlen &lt;span class=&#34;number&#34;&gt;64&lt;/span&gt;  scopeid &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x20&amp;lt;link&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;ether&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;00&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;c:&lt;span class=&#34;number&#34;&gt;29&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;28&lt;/span&gt;:c0:&lt;span class=&#34;number&#34;&gt;82&lt;/span&gt;  txqueuelen &lt;span class=&#34;number&#34;&gt;1000&lt;/span&gt;  (Ethernet)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;RX&lt;/span&gt; packets &lt;span class=&#34;number&#34;&gt;114664&lt;/span&gt;  bytes &lt;span class=&#34;number&#34;&gt;143722941&lt;/span&gt; (&lt;span class=&#34;number&#34;&gt;143&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt; MB)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;RX&lt;/span&gt; errors &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  dropped &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  overruns &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  frame &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;TX&lt;/span&gt; packets &lt;span class=&#34;number&#34;&gt;52086&lt;/span&gt;  bytes &lt;span class=&#34;number&#34;&gt;37199464&lt;/span&gt; (&lt;span class=&#34;number&#34;&gt;37&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt; MB)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;TX&lt;/span&gt; errors &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  dropped &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt; overruns &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  carrier &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  collisions &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attribute&#34;&gt;lo&lt;/span&gt;: flags=&lt;span class=&#34;number&#34;&gt;73&lt;/span&gt;&amp;lt;UP,LOOPBACK,RUNNING&amp;gt;  mtu &lt;span class=&#34;number&#34;&gt;65536&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;inet&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;127.0.0.1&lt;/span&gt;  netmask &lt;span class=&#34;number&#34;&gt;255.0.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;inet6&lt;/span&gt; ::&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;  prefixlen &lt;span class=&#34;number&#34;&gt;128&lt;/span&gt;  scopeid &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x10&amp;lt;host&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;loop&lt;/span&gt;  txqueuelen &lt;span class=&#34;number&#34;&gt;1000&lt;/span&gt;  (Local Loopback)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;RX&lt;/span&gt; packets &lt;span class=&#34;number&#34;&gt;14643&lt;/span&gt;  bytes &lt;span class=&#34;number&#34;&gt;53874531&lt;/span&gt; (&lt;span class=&#34;number&#34;&gt;53&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt; MB)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;RX&lt;/span&gt; errors &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  dropped &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  overruns &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  frame &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;TX&lt;/span&gt; packets &lt;span class=&#34;number&#34;&gt;14643&lt;/span&gt;  bytes &lt;span class=&#34;number&#34;&gt;53874531&lt;/span&gt; (&lt;span class=&#34;number&#34;&gt;53&lt;/span&gt;.&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt; MB)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attribute&#34;&gt;TX&lt;/span&gt; errors &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  dropped &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt; overruns &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  carrier &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;  collisions &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attribute&#34;&gt;weidows&lt;/span&gt;@ubuntu-server:~/Code$&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;可以看到第三行&lt;code&gt;192.168.2.122&lt;/code&gt;就是分配的 ip 了,用它就行.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;进入&lt;code&gt;/etc/netplan/&lt;/code&gt;这个目录,使用&lt;code&gt;ll&lt;/code&gt;查看内部有啥东西&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;发现第六行&lt;code&gt;00-installer-config.yaml&lt;/code&gt;这个文件是我们要找的(可能名字不一样,后缀是.yaml 就对了)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;使用&lt;code&gt;cat&lt;/code&gt;查看文件内容,核实没错,然后修改它!&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight jboss-cli&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;weidows@ubuntu-server:~&lt;span class=&#34;string&#34;&gt;/Code&lt;/span&gt;$ &lt;span class=&#34;keyword&#34;&gt;cd&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;/etc/netplan/&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;weidows@ubuntu-server:&lt;span class=&#34;string&#34;&gt;/etc/netplan&lt;/span&gt;$ ll&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;total 12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;drwxr-xr-x  2 root root 4096 Feb  1 17&lt;span class=&#34;function&#34;&gt;:55&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;./&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;drwxr-xr-x 92 root root 4096 Feb  2 06&lt;span class=&#34;function&#34;&gt;:25&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;../&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;-rw-r&lt;span class=&#34;params&#34;&gt;--r--&lt;/span&gt;  1 root root  116 Feb  1 17&lt;span class=&#34;function&#34;&gt;:55&lt;/span&gt; 00-installer-config.yaml&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;weidows@ubuntu-server:&lt;span class=&#34;string&#34;&gt;/etc/netplan&lt;/span&gt;$ cat 00-installer-config.yaml&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# This is the network config written by &amp;#x27;subiquity&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;network:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  ethernets:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ens33:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      dhcp4: &lt;span class=&#34;literal&#34;&gt;true&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;keyword&#34;&gt;version&lt;/span&gt;: 2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;weidows@ubuntu-server:&lt;span class=&#34;string&#34;&gt;/etc/netplan&lt;/span&gt;$&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;使用&lt;code&gt;vi&lt;/code&gt;修改&lt;code&gt; sudo vi /etc/netplan/00-installer-config.yaml&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;地址啥的按照规则设&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight yaml&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;## This is the network config written by &amp;#x27;subiquity&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;attr&#34;&gt;network:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;ethernets:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;attr&#34;&gt;ens33:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;dhcp4:&lt;/span&gt; &lt;span class=&#34;literal&#34;&gt;false&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;addresses:&lt;/span&gt; [&lt;span class=&#34;number&#34;&gt;192.168&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;.2&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;.122&lt;/span&gt;&lt;span class=&#34;string&#34;&gt;/24&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;gateway4:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;192.168&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;.2&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;.1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &lt;span class=&#34;attr&#34;&gt;nameservers:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;attr&#34;&gt;addresses:&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          &lt;span class=&#34;bullet&#34;&gt;-&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;192.168&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;.2&lt;/span&gt;&lt;span class=&#34;number&#34;&gt;.1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;attr&#34;&gt;version:&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;然后应用&lt;code&gt;sudo netplan apply&lt;/code&gt;设置,完事!&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;a&gt;&lt;img src= &#34;https://pan.weidows.tech/d/local/img/loading.svg&#34; data-lazy-src=&#34;https://pan.weidows.tech/d/local/img/divider.png&#34; alt=&#34;分割线&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;h2 id=&#34;软件备份&#34;&gt;软件备份&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;找软件的话可以用&lt;code&gt;apt search XXX&lt;/code&gt;来找&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;个人安装的一些服务型软件(在主机上做的开发,用这个 Server 跑服务)&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;sudo&lt;/span&gt; apt install docker&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;sudo&lt;/span&gt; apt install net-tools&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;
